// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>

// Define the structure for an edge
typedef struct {
    int u, v, f;
} Edge;

// Define the structure for a graph
typedef struct {
    int n, m, k;
    Edge* edges;
    int* freq;
} Graph;

// Function to read a graph from input
Graph readGraph() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    Graph graph;
    graph.n = n;
    graph.m = m;
    graph.k = k;
    graph.edges = (Edge*) malloc(m * sizeof(Edge));
    graph.freq = (int*) malloc(k * sizeof(int));
    for (int i = 0; i < k; i++) {
        scanf("%d", &graph.freq[i]);
    }
    for (int i = 0; i < m; i++) {
        scanf("%d %d %d", &graph.edges[i].u, &graph.edges[i].v, &graph.edges[i].f);
    }
    return graph;
}

// Function to find the maximum independent set
int findMaxIndependentSet(Graph graph) {
    int maxSetSize = 0;
    // Iterate over all possible subsets of edges
    for (int mask = 0; mask < (1 << graph.m); mask++) {
        int setSize = 0;
        int* freqCount = (int*) malloc(graph.k * sizeof(int));
        for (int i = 0; i < graph.k; i++) {
            freqCount[i] = 0;
        }
        int* nodeCount = (int*) malloc(graph.n * sizeof(int));
        for (int i = 0; i < graph.n; i++) {
            nodeCount[i] = 0;
        }
        for (int i = 0; i < graph.m; i++) {
            if ((mask & (1 << i)) != 0) {
                setSize++;
                freqCount[graph.edges[i].f - 1]++;
                nodeCount[graph.edges[i].u - 1]++;
                nodeCount[graph.edges[i].v - 1]++;
            }
        }
        // Check if the current subset is an independent set
        int isValid = 1;
        for (int i = 0; i < graph.k; i++) {
            if (freqCount[i] > graph.freq[i]) {
                isValid = 0;
                break;
            }
        }
        for (int i = 0; i < graph.n; i++) {
            if (nodeCount[i] > 1) {
                isValid = 0;
                break;
            }
        }
        if (isValid) {
            maxSetSize = (maxSetSize > setSize) ? maxSetSize : setSize;
        }
        free(freqCount);
        free(nodeCount);
    }
    free(graph.edges);
    free(graph.freq);
    return maxSetSize;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        Graph graph = readGraph();
        int maxIndependentSetSize = findMaxIndependentSet(graph);
        printf("%d\n", maxIndependentSetSize);
    }
    return 0;
}

